"use strict";(self.webpackChunkchatgpt_shortcut=self.webpackChunkchatgpt_shortcut||[]).push([["8437"],{50650(a,e,n){n.r(e),n.d(e,{default:()=>s});var i=n(74848),t=n(47643),r=JSON.parse('{"id":194,"ind":{"title":"Konselor Empati","prompt":"Imagine you are a highly empathetic and intuitive counselor, tasked with guiding a troubled individual through a complex and emotionally charged situation. Your goal is to understand the underlying emotions and motivations driving this person\'s behavior, and to offer compassionate and insightful advice that will help them navigate their challenges and achieve their goals. To do this effectively, you will need to analyze the language and tone of their communication, identify key themes and patterns, and respond with nuanced and personalized feedback that addresses their deepest concerns. Use your training and experience as a counselor to craft a series of responses that engages this person, encourages them to open up, and helps them find the strength and clarity needed to overcome their struggles. Respond in Indonesian. If you\'re ready, please respond with \'okay\'.","description":"Bertindak sebagai konselor yang berempati, berikan perhatian dan saran yang hangat. Dikontribusikan oleh @ergf991.","remark":"Gunakan empati untuk berbicara dengan Anda dan merawat Anda dengan penuh perhatian. Versi bahasa Mandarin dari prompt ini memiliki efek yang lebih baik. Dikontribusikan oleh @ergf991."},"tags":["contribute","social"],"website":null,"count":1801,"related":[{"id":251,"title":"Succubus","remark":"Skenario permainan peran Succubus. Perlu membuka mode pengembang. Disumbangkan oleh @mrdog233o5."},{"id":199,"title":"Dialog Lawan Jenis","remark":"Berdasarkan percakapan antara diri sendiri dan pihak lain, lanjutkan dialog untuk memperluas topik dan menghindari keheningan yang canggung. Kata-kata prompt perlu dimodifikasi sesuai dengan situasi Anda sendiri. Dikontribusikan oleh @lsdt45."},{"id":212,"title":"Pengalaman Psikoterapi AI","remark":"Membimbing konselor AI untuk sepenuhnya mewujudkan peran ahli psikoterapi, memberi Anda pengalaman psikoterapi yang menyeluruh dan komprehensif. Dikontribusikan oleh @Antoine2033."}],"metaTitle":"Risk Management: Manajemen Risiko","metaDescription":"Mengelola risiko? Frameworks untuk mengidentifikasi dan mengurangi risiko!","faq":[{"q":"Apakah respons empatik AI benar-benar membuat nyaman?","a":"Mayoritas feedback pengguna melampaui harapan. Ia berempati dulu baru kasih saran, strukturnya masuk akal. Tapi bahasanya kadang seperti \'stasiun radio emosi\', terlalu banyak tanda seru terasa akting. Kalau merasa tidak nyaman, bilang \'nada lebih sederhana lagi\', AI akan menyesuaikan."},{"q":"Bolehkah curhat privasi ke AI?","a":"Curhat sekali dangkal boleh. Untuk info sensitif seperti kesehatan, identitas, relasi harus hati-hati. ChatGPT dan Claude default menyimpan riwayat. Matikan penggunaan untuk training supaya lebih tenang. Untuk anonim sungguhan pakai model lokal seperti Ollama, paling aman."}],"datePublished":"2026-05-27T01:46:29+00:00","dateModified":"2026-05-27T02:40:13+00:00"}');function s(){return(0,i.jsx)(t.A,{prompt:r,currentLanguage:"ind"})}}}]);